            freeze_message: __('Creating BOMs...'),
            callback(r) {
                if (!r.message) {
                    frappe.msgprint({
                        title: __('Error'),
                        message: __('No response from server'),
                        indicator: 'red'
                    });
                    return;
                }

                const msg = r.message;
                let error_html = '';

                if (msg.errors && msg.errors.length > 0) {
                    error_html = '<br><br><strong>Errors:</strong><br>' + msg.errors.join('<br>');
