## 3. BOM Upload Modification Logic

### New Enhanced Flow:

```python
@frappe.whitelist()
def create_boms(docname):
    doc = frappe.get_doc("BOM Upload", docname)

    # Step 1: Parse Excel (existing logic)
    file_doc = frappe.get_doc("File", {"file_url": doc.bom_file})
    content = file_doc.get_content()
    wb = openpyxl.load_workbook(io.BytesIO(content), data_only=True)
    ws = wb.active
    rows = parse_rows(ws)
    tree = build_tree(rows)

    # Step 2: NEW - Analyze upload with change detection
    analysis = analyze_upload(tree, doc.project)

    # Step 3: NEW - Check for blocking issues
    if analysis['loose_blocked']:
        return {
            "status": "blocked",
            "reason": "loose_items_not_enabled",
            "blocked_items": analysis['loose_blocked'],
            "message": "Enable 'Can be converted to BOM' for loose items first"
        }

    if analysis['changed_components']:
        # Show blocking dialog for user resolution
        return {
            "status": "requires_resolution",
            "analysis": analysis,
            "message": "Some components have changed. Resolve before proceeding."
        }

    # Step 4: Create BOMs for allowed components
    results = {
        "created": 0,
        "skipped": 0,
        "failed": 0,
        "errors": [],
        "component_masters_created": 0
    }

    for node in analysis['can_create']:
        try:
            # Create/update Component Master
            component_master = create_or_update_component_master(node, doc.project)
            if component_master.get('created'):
                results['component_masters_created'] += 1

            # Create BOM (existing logic)
            created_flag = create_bom_recursive(node, doc.project)
            if created_flag:
                results['created'] += 1

                # Update Component Master with BOM reference
                update_component_bom_reference(node['item_code'], doc.project)
            else:
                results['skipped'] += 1

        except Exception as e:
            results['failed'] += 1
            results['errors'].append(f"{node['item_code']} → {str(e)}")

    return results


def analyze_upload(tree, project):
    """
    Analyze upload tree for:
    1. New components
    2. Changed components (BOM structure changed)
    3. Loose items not enabled for conversion
    4. Dependencies and blocking
    """

    # Build flat list of all components in upload
    all_components = flatten_tree(tree)

    # Build dependency graph
    graph = {}
    for comp in all_components:
        graph[comp['item_code']] = {
            'node': comp,
            'children': [c['item_code'] for c in comp['children']],
            'status': None  # Will determine
        }

    # Categorize each component
    categorized = {
        'new': [],
        'unchanged': [],
        'changed': [],
        'loose_blocked': []
    }

    for item_code, data in graph.items():
        status, details = determine_component_status(item_code, data['node'], project)
        data['status'] = status
        data['details'] = details
        categorized[status].append(item_code)

    # Find blocking dependencies
    changed_set = set(categorized['changed'])
    loose_blocked_set = set(categorized['loose_blocked'])
    blocked_by_changes = {}

    for item_code, data in graph.items():
        if data['status'] in ['new', 'unchanged']:
            # Check if any child is changed or loose-blocked
            blocking_children = []

            for child_code in data['children']:
                if child_code in changed_set:
                    blocking_children.append({
                        'item': child_code,
                        'reason': 'BOM structure changed'
                    })
                elif child_code in loose_blocked_set:
                    blocking_children.append({
                        'item': child_code,
                        'reason': 'Loose item conversion not enabled'
                    })
                # Recursive check for nested blocking
                elif child_code in blocked_by_changes:
                    blocking_children.append({
                        'item': child_code,
                        'reason': f'Depends on {blocked_by_changes[child_code]}'
                    })

            if blocking_children:
                blocked_by_changes[item_code] = blocking_children

    # Build result
    can_create = []
    for item_code in categorized['new'] + categorized['unchanged']:
        if item_code not in blocked_by_changes:
            can_create.append(graph[item_code]['node'])

    return {
        'can_create': can_create,
        'changed_components': [graph[ic] for ic in categorized['changed']],
        'loose_blocked': [graph[ic] for ic in categorized['loose_blocked']],
        'blocked_by_dependencies': blocked_by_changes,
        'summary': {
            'total': len(all_components),
            'new': len(categorized['new']),
            'unchanged': len(categorized['unchanged']),
            'changed': len(categorized['changed']),
            'loose_blocked': len(categorized['loose_blocked']),
            'can_create': len(can_create),
            'blocked': len(blocked_by_changes)
        }
    }


def determine_component_status(item_code, node, project):
    """
    Determine if component is new, unchanged, or changed
    Returns: (status, details)
    """

    # Check if Component Master exists
    component_master = frappe.db.get_value(
        "Project Component Master",
        {"project": project, "item_code": item_code},
        ["name", "is_loose_item", "can_be_converted_to_bom", "bom_structure_hash", "active_bom"],
        as_dict=True
    )

    if not component_master:
        # NEW COMPONENT
        return "new", {"first_time": True}

    # Check if it's a loose item without conversion enabled
    if component_master.is_loose_item and not component_master.can_be_converted_to_bom:
        return "loose_blocked", {
            "component_master": component_master.name,
            "message": f"Loose item {item_code} not enabled for BOM conversion"
        }

    # Component exists - check if BOM changed
    if not component_master.active_bom:
        # Had no BOM before, now has one
        return "changed", {
            "change_type": "new_bom",
            "component_master": component_master.name
        }

    # Compare BOM structures
    new_hash = calculate_bom_structure_hash(node['children'])
    existing_hash = component_master.bom_structure_hash

    if new_hash != existing_hash:
        # BOM STRUCTURE CHANGED
        procurement_docs = get_procurement_documents(project, item_code)
        return "changed", {
            "change_type": "bom_structure",
            "component_master": component_master.name,
            "old_bom": component_master.active_bom,
            "old_hash": existing_hash,
            "new_hash": new_hash,
            "procurement_status": procurement_docs
        }

    # UNCHANGED
    return "unchanged", {
        "component_master": component_master.name,
        "bom": component_master.active_bom
    }


def calculate_bom_structure_hash(children):
    """
    Create hash of BOM structure for comparison
    Format: sorted list of (item_code, qty) tuples
    """
    structure = sorted(
        [(child['item_code'], float(child['qty'])) for child in children],
        key=lambda x: x[0]
    )
    return hashlib.md5(str(structure).encode()).hexdigest()


def create_or_update_component_master(node, project):
    """
    Create or update Project Component Master entry
    Returns: {'created': True/False, 'name': doc.name}
    """

    existing = frappe.db.exists("Project Component Master", {
        "project": project,
        "item_code": node['item_code']
    })

    if existing:
        # Update existing
        doc = frappe.get_doc("Project Component Master", existing)
        doc.bom_level = node['level']
        doc.has_bom = 1 if node['children'] else 0
        doc.bom_structure_hash = calculate_bom_structure_hash(node['children'])

        # Update BOM usage tracking
        # (Will be done after BOM is created)

        doc.save(ignore_permissions=True)
        return {'created': False, 'name': doc.name}

    else:
        # Create new
        doc = frappe.get_doc({
            "doctype": "Project Component Master",
            "project": project,
            "item_code": node['item_code'],
            "item_name": node['description'],
            "bom_level": node['level'],
            "has_bom": 1 if node['children'] else 0,
            "is_loose_item": 0,
            "design_status": "Design Released",
            "bom_structure_hash": calculate_bom_structure_hash(node['children'])
        })
        doc.insert(ignore_permissions=True)
        return {'created': True, 'name': doc.name}


def update_component_bom_reference(item_code, project):
    """
    After BOM is created, update Component Master with BOM reference
    """
    # Get the newly created/active BOM
    bom_name = frappe.db.get_value("BOM", {
        "item": item_code,
        "is_active": 1,
        "is_default": 1
    }, "name")

    if bom_name:
        component = frappe.get_doc("Project Component Master", {
            "project": project,
            "item_code": item_code
        })
        component.active_bom = bom_name
        component.save(ignore_permissions=True)
```

