## 5. Client-Side: Change Resolution Dialog

### bom_upload.js modification:

```javascript
frappe.ui.form.on('BOM Upload', {
    refresh: function(frm) {
        if (frm.doc.bom_file) {
            frm.add_custom_button(__('Create BOMs'), function() {
                create_boms_with_validation(frm);
            }).addClass('btn-primary');
        }
    }
});

function create_boms_with_validation(frm) {
    frappe.call({
        method: 'clevertech.doctype.bom_upload.bom_upload.create_boms',
        args: { docname: frm.doc.name },
        freeze: true,
        freeze_message: __('Analyzing BOM upload...'),
        callback: function(r) {
            if (r.message.status === 'blocked') {
                show_loose_items_blocked_dialog(r.message);
            } 
            else if (r.message.status === 'requires_resolution') {
                show_change_resolution_dialog(r.message.analysis, frm);
            }
            else {
                show_upload_results(r.message);
            }
        }
    });
}

function show_loose_items_blocked_dialog(data) {
    let html = `
        <div class="alert alert-danger">
            <h5>Loose Items Blocking BOM Creation</h5>
            <p>The following loose items must have "Can be converted to BOM" enabled first:</p>
            <ul>
                ${data.blocked_items.map(item => `
                    <li><b>${item.node.item_code}</b> - ${item.details.message}</li>
                `).join('')}
            </ul>
            <p>Please enable conversion in Project Component Master, then re-run upload.</p>
        </div>
    `;

    frappe.msgprint({
        title: __('Upload Blocked'),
        message: html,
        indicator: 'red'
    });
}

function show_change_resolution_dialog(analysis, frm) {
    let changed_components = analysis.changed_components;
    let blocked_components = analysis.blocked_by_dependencies;

    let html = `
        <div class="bom-change-resolution">
            <h5>BOM Upload Analysis</h5>

            <div class="summary" style="margin-bottom: 20px;">
                <table class="table table-bordered table-sm">
                    <tr>
                        <td>✓ Can Create Immediately:</td>
                        <td><b>${analysis.summary.can_create}</b> components</td>
                    </tr>
                    <tr class="text-warning">
                        <td>⚠ Changed Components:</td>
                        <td><b>${analysis.summary.changed}</b> components</td>
                    </tr>
                    <tr class="text-danger">
                        <td>⛔ Blocked by Dependencies:</td>
                        <td><b>${analysis.summary.blocked}</b> components</td>
                    </tr>
                </table>
            </div>

            ${changed_components.length > 0 ? `
                <div class="changed-components" style="margin-bottom: 20px;">
                    <h6 class="text-warning">⚠ Changed Components Requiring Resolution:</h6>
                    ${changed_components.map((comp, idx) => `
                        <div class="card mb-2">
                            <div class="card-body">
                                <h6>[${idx+1}/${changed_components.length}] ${comp.node.item_code}</h6>
                                <p><b>Change Type:</b> ${comp.details.change_type}</p>
                                <p><b>Old BOM:</b> ${comp.details.old_bom || 'None'}</p>
                                ${comp.details.procurement_status ? `
                                    <p class="text-danger">
                                        <b>⚠ Procurement Status:</b> 
                                        ${JSON.stringify(comp.details.procurement_status)}
                                    </p>
                                ` : ''}
                                <p><small>You must manually deactivate old BOM and re-run upload.</small></p>
                            </div>
                        </div>
                    `).join('')}
                </div>
            ` : ''}

            ${Object.keys(blocked_components).length > 0 ? `
                <div class="blocked-components">
                    <h6 class="text-danger">⛔ Components Blocked by Dependencies:</h6>
                    <ul>
                        ${Object.entries(blocked_components).map(([item, reasons]) => `
                            <li>
                                <b>${item}</b>
                                <ul>
                                    ${reasons.map(r => `
                                        <li>${r.item}: ${r.reason}</li>
                                    `).join('')}
                                </ul>
                            </li>
                        `).join('')}
                    </ul>
                </div>
            ` : ''}

            <hr>
            <p><b>Actions:</b></p>
            <ol>
                <li>Review changed components above</li>
                <li>Manually deactivate old BOMs in BOM List</li>
                <li>Re-run "Create BOMs" to complete upload</li>
            </ol>
        </div>
    `;

    frappe.msgprint({
        title: __('BOM Changes Detected - Resolution Required'),
        message: html,
        indicator: 'orange',
        primary_action: {
            label: __('Open BOM List'),
            action: function() {
                frappe.set_route('List', 'BOM', {
                    'item': ['in', changed_components.map(c => c.node.item_code)],
                    'is_active': 1
                });
            }
        }
    });
}

function show_upload_results(results) {
    let html = `
        <div class="alert alert-success">
            <h5>BOM Upload Complete</h5>
            <table class="table table-sm">
                <tr><td>✓ BOMs Created:</td><td><b>${results.created}</b></td></tr>
                <tr><td>○ Skipped (Unchanged):</td><td><b>${results.skipped}</b></td></tr>
                <tr><td>✗ Failed:</td><td><b>${results.failed}</b></td></tr>
                <tr><td>📋 Component Masters Created:</td><td><b>${results.component_masters_created}</b></td></tr>
            </table>
            ${results.errors.length > 0 ? `
                <hr>
                <h6>Errors:</h6>
                <ul>${results.errors.map(e => `<li>${e}</li>`).join('')}</ul>
            ` : ''}
        </div>
    `;

    frappe.msgprint({
        title: __('Success'),
        message: html,
        indicator: 'green'
    });
}
