## 6. Report: Component Procurement Status

### Report Configuration:

```python
# clevertech/report/component_procurement_status/component_procurement_status.py

import frappe

def execute(filters=None):
    columns = get_columns()
    data = get_data(filters)
    return columns, data

def get_columns():
    return [
        {"label": "Project", "fieldname": "project", "fieldtype": "Link", "options": "Project", "width": 150},
        {"label": "Component Code", "fieldname": "item_code", "fieldtype": "Link", "options": "Item", "width": 150},
        {"label": "Component Name", "fieldname": "item_name", "fieldtype": "Data", "width": 200},
        {"label": "BOM Level", "fieldname": "bom_level", "fieldtype": "Int", "width": 80},
        {"label": "Parent Component", "fieldname": "parent_component", "fieldtype": "Data", "width": 150},
        {"label": "Has BOM", "fieldname": "has_bom", "fieldtype": "Check", "width": 80},
        {"label": "Is Loose Item", "fieldname": "is_loose_item", "fieldtype": "Check", "width": 100},
        {"label": "Design Status", "fieldname": "design_status", "fieldtype": "Data", "width": 120},
        {"label": "Budgeted Rate", "fieldname": "budgeted_rate", "fieldtype": "Currency", "width": 120},
        {"label": "Qty Limit", "fieldname": "total_qty_limit", "fieldtype": "Float", "width": 100},
        {"label": "Qty Procured", "fieldname": "total_qty_procured", "fieldtype": "Float", "width": 100},
        {"label": "Balance", "fieldname": "procurement_balance", "fieldtype": "Float", "width": 100},
        {"label": "Procurement Status", "fieldname": "procurement_status", "fieldtype": "Data", "width": 150},
        {"label": "Active BOM", "fieldname": "active_bom", "fieldtype": "Link", "options": "BOM", "width": 150},
        {"label": "Target Date", "fieldname": "target_delivery_date", "fieldtype": "Date", "width": 100},
    ]

def get_data(filters):
    conditions = "WHERE 1=1"

    if filters.get("project"):
        conditions += f" AND pcm.project = '{filters.get('project')}'"

    if filters.get("procurement_status"):
        conditions += f" AND pcm.procurement_status = '{filters.get('procurement_status')}'"

    if filters.get("is_loose_item"):
        conditions += " AND pcm.is_loose_item = 1"

    data = frappe.db.sql(f"""
        SELECT 
            pcm.project,
            pcm.item_code,
            pcm.item_name,
            pcm.bom_level,
            pcm.parent_component,
            pcm.has_bom,
            pcm.is_loose_item,
            pcm.design_status,
            pcm.budgeted_rate,
            pcm.total_qty_limit,
            pcm.total_qty_procured,
            pcm.procurement_balance,
            pcm.procurement_status,
            pcm.active_bom,
            pcm.target_delivery_date
        FROM `tabProject Component Master` pcm
        {conditions}
        ORDER BY pcm.project, pcm.bom_level, pcm.item_code
    """, as_dict=1)

    return data
```

