/**
 * Project Form Customizations
 *
 * Adds custom buttons and functionality to the Project form.
 */

frappe.ui.form.on('Project', {
    refresh: function(frm) {
        // Only show button if project is saved
        if (!frm.is_new()) {
            // Add button to generate Component Masters from existing BOMs
            frm.add_custom_button(__('Generate Component Masters from BOMs'), function() {
                generate_component_masters_from_boms(frm);
            }, __('Actions'));
        }
    }
});


function generate_component_masters_from_boms(frm) {
    // Confirm before proceeding
    frappe.confirm(
        __('This will create Project Component Master records for all items with active BOMs in project <b>{0}</b>.<br><br>Existing Component Masters will be skipped.<br><br>Do you want to continue?', [frm.doc.name]),
        function() {
            // User confirmed - proceed with generation
            frappe.call({
                method: 'clevertech.project_component_master.bulk_generation.generate_component_masters_from_boms',
                args: {
                    project: frm.doc.name
                },
                freeze: true,
                freeze_message: __('Generating Component Masters...'),
                callback: function(r) {
                    if (r.message) {
                        // Show detailed results in console for debugging
                        console.log('Bulk Generation Results:', r.message);

                        // Refresh form to show any updates
                        frm.reload_doc();
                    }
                },
                error: function(r) {
                    frappe.msgprint({
                        title: __('Error'),
                        indicator: 'red',
                        message: __('Failed to generate Component Masters. Check Error Log for details.')
                    });
                }
            });
        },
        function() {
            // User cancelled
            frappe.show_alert({
                message: __('Operation cancelled'),
                indicator: 'orange'
            }, 3);
        }
    );
}
